VALUES
  ('aboriginal-6e11b43e-moex-00272', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-6ed013db', 'sub-aboriginal-6e11b43e-07', NULL, 'single_choice', '下列對原住民族基本法第21條的諮商同意權那一項是不正確的？', '["政府或私人於原住民族土地或部落及其周邊一定範圍內之公有土地從事土地開發、資源利用、生態 保育及學術研究，應諮商並取得原住民族或部落同意或參與，原住民得分享相關利益", "政府或法令限制原住民族利用前項土地及自然資源時，應與原住民族、部落或原住民諮商，並取得 其同意", "政府或法令限制原住民族利用前項土地及自然資源時，受限制所生之損失，應由該主管機關寬列預 算補償之", "政府或法令限制原住民族利用前項土地開發及自然資源營利所得，應提撥一定比例給當地原民教會 或實驗學校，作為回饋經費"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00273', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-6ed013db', 'sub-aboriginal-6e11b43e-07', NULL, 'single_choice', '原住民族教育法在 108 年修正時有 5 大重點，包括擴大原住民族教育對象到全民、完備行政支持系 統、促進原住民族參與、強化師資培育與深化民族教育。下列何者不是該法條內容？', '["各級教育主管機關推動教育政策，應促進全體國民認識與尊重原住民族", "各級教育主管機關並得鼓勵、補助非營利之機構、法人或團體，對社會大眾進行原住民族及多元文 化教育", "政府機關、公營事業機構及政府捐助基金累計超過百分之五十之財團法人，應規劃實施原住民族及 多元文化教育相關課程或活動，並鼓勵其員工參與", "各級政府對於原住民族教師團體及人員，應予獎勵"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00274', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-6ed013db', 'sub-aboriginal-6e11b43e-07', NULL, 'single_choice', '依照原住民族工作權保障法，有關公共工程及政府採購之保障，下列何者正確？', '["各級政府機關、公立學校及公營事業機構，辦理位於原住民地區政府採購法公告金額之採購，應由 原住民個人、機構、法人或團體承包", "各級政府機關、公立學校及公營事業機構，辦理位於原住民地區未達政府採購法公告金額之採購， 應由原住民個人、機構、法人或團體承包。但原住民個人、機構、法人或團體無法承包者，不在此限", "各級政府機關、公立學校及公營事業機構，辦理位於原住民地區之政府採購應由原住民或新住民個 人、機構、法人或教會團體輪流承包", "各級政府機關、公立學校及公營事業機構，辦理位於原住民地區之政府採購應由原住民合作社、原 住民青年、婦女團體承包"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00275', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-6ed013db', 'sub-aboriginal-6e11b43e-07', NULL, 'single_choice', '依照原住民族工作權保障法，中央主管機關應於原住民族綜合發展基金項下設置就業基金，作為辦理 促進原住民就業權益相關事項；其收支、保管及運用辦法，由行政院定之。下列何者不是前項就業基 金之來源？', '["政府循預算程序之撥款", "各級政府機關、公立學校及公營事業機構僱用、進用原住民之人數未達所定比例者，依規定所繳納 之代金", "原住民族綜合發展基金之孳息收入", "雇主聘僱移工繳納的就業安定基金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00276', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-6ed013db', 'sub-aboriginal-6e11b43e-07', NULL, 'single_choice', '根據長期照顧服務機構設立許可及管理辦法，若是申請於原住民族地區籌設或設立設有機構住宿式服 務以外之長照機構時，因該地區未設有公、私立長照機構，且因地理條件限制，難以覓得符合長照機 構設立要件之場地及長期照顧服務機構設立標準所定各類專業人員，則其機構所在之建築物，於領有 第8條第5款合法使用證明文件或第12條第1項第3款建築物使用執照前，得以取得什麼證明文件， 以及經直轄市、縣（市）消防主管機關查驗合格之簡易消防安全設備配置平面圖替代之？', '["申請人承諾改善消防安全切結書", "執業之建築師、土木工程科技師或結構工程科技師出具之結構安全鑑定證明文件", "四鄰證明文件", "投保公共意外責任保險之保險單影本"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00277', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-6ed013db', 'sub-aboriginal-6e11b43e-07', NULL, 'single_choice', '下列何者不是原住民族基本法規範的內容？', '["政府於原住民族地區劃設國家公園、國家級風景特定區、林業區、生態保育區、遊樂區及其他資源 治理機關時，應徵得當地原住民族同意，並與原住民族建立共同管理機制", "為發展及厚植原住民族知識體系，中央原住民族主管機關應會商教育、科技、文化等主管機關，建 構原住民族知識體系中長程計畫，並積極獎勵原住民族學術及各原住民族知識研究", "政府應依原住民族特性，策訂原住民族公共衛生及醫療政策，將原住民族地區納入全國醫療網，辦 理原住民族健康照顧，建立完善之長期照護、緊急救護及後送體系，保障原住民健康及生命安全", "政府應尊重原住民族傳統醫藥和保健方法，並進行研究與推廣"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00278', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-6ed013db', 'sub-aboriginal-6e11b43e-07', NULL, 'single_choice', '有關原住民族身分取得與喪失的認定何者正確？', '["原住民為非原住民收養者，其原住民身分喪失", "未滿7歲之非原住民為年滿40歲且無子女之原住民父母收養者，得取得原住民身分", "非原住民為原住民父母收養者，不得取得原住民身分", "非原住民因婚姻關係得取得原住民身分，婚姻關係終止時，原住民身分自動喪失"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00279', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-6ed013db', 'sub-aboriginal-6e11b43e-07', NULL, 'single_choice', '依照原住民族傳統智慧創作保護條例的規定，有關原住民族傳統智慧創作申請人應以何者為限？', '["原住民族或學者專家", "原住民族或部落", "原住民族部落會議或部落公法人", "原住民族文化協會或文化局"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00280', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-6ed013db', 'sub-aboriginal-6e11b43e-07', NULL, 'single_choice', 'Thedesignofmyhighschooldidnotappealtomebecauseitwasbuiltto only200students.', '["barricade", "accommodate", "withold", "embrace"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00281', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-6ed013db', 'sub-aboriginal-6e11b43e-07', NULL, 'single_choice', 'Thejuryshouldcarefullyreviewthewitnesses’ andassesstheircredibilitybeforetheyreachaverdict.', '["criticism", "evidence", "indictment", "testimony"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "80ae72992682", "answer_pdf_sha1": "09be54dfa1cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0221", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL)
